// Determine which lists to sync
const token = $('Get SF OAuth Token').first().json.access_token;
const body  = $('Webhook').first().json.body || {};
const listId   = body.list_id   || null;
const listName = body.list_name || null;
const mode     = body.mode      || 'memberships_only';

return [{ json: { token, listId, listName, mode, startedAt: new Date().toISOString() } }];

// Route: specific list_id provided — build single-item array
const req = $('Parse Request').first().json;
return [{ json: { AE_List_ID__c: String(req.listId), Name: String(req.listId), token: req.token } }];

// Route: all lists — expand SF records into individual items
const token  = $('Parse Request').first().json.token;
const records = $('Get All Active Lists from SF').first().json.records || [];
return records.map(r => ({ json: { AE_List_ID__c: r.AE_List_ID__c, Name: r.Name, token } }));

const token  = $('Parse Request').first().json.token;
const listId = $('Parse Request').first().json.listId;
// Filter out members with null prospectId (Pardot data quality issue)
const members = ($input.first().json.values || []).filter(m => m.prospectId != null);

const records = members.map(m => {
  const sfId = (m.prospect && m.prospect.salesforceId) || null;
  const rec = {
    attributes:           { type: 'AE_List_Membership__c' },
    Membership_Key__c:    `${m.listId}-${m.prospectId}`,
    AE_Prospect_ID__c:    String(m.prospectId),
    'AE_List__r':         { AE_List_ID__c: String(m.listId) },
    Active_Membership__c: !m.optedOut,
    Date_Added__c:        m.createdAt ? m.createdAt.split('T')[0] : null,
  };
  if (sfId && sfId.startsWith('003')) rec.Contact__c = sfId;
  else if (sfId && sfId.startsWith('00Q')) rec.Lead__c = sfId;
  return rec;
});

const linked   = records.filter(r => r.Contact__c || r.Lead__c).length;
const unlinked = records.length - linked;
return [{ json: { listId, token, records, count: records.length, linked, unlinked } }];

// SF Composite API returns array; n8n HTTP Request splits into N items
const items = $input.all().map(i => i.json);
const sfResults = items.filter(r => r && ('success' in r));
const inserted = sfResults.filter(r => r.success === true  && r.created === true).length;
const updated  = sfResults.filter(r => r.success === true  && r.created === false).length;
const errors   = sfResults.filter(r => r.success === false).length;
const listId   = $('Parse Request').first().json.listId || 'all';
return [{ json: { listId, inserted, updated, errors, total: sfResults.length, completedAt: new Date().toISOString() } }];

